<template><div class="grid"><img v-for="(img,i) in images" :src="img" @click="open(i)" class="thumb"/></div><div v-if="show" class="full" @click="close"><button @click.stop="prev">⟨</button><img :src="current" class="fullimg"/><button @click.stop="next">⟩</button></div></template><script setup>import {ref,computed} from "vue";const props=defineProps({images:Array});const i=ref(0),show=ref(false);const current=computed(()=>props.images[i.value]);const open=j=>{i.value=j;show.value=true};const close=()=>show.value=false;const next=()=>i.value=(i.value+1)%props.images.length;const prev=()=>i.value=(i.value-1+props.images.length)%props.images.length;</script>